// Grab the element we want to listen on
var clickId = document.getElementById('clickme');

// First argument is the event to listen for, second is what runs when it fires, third one I'll cover later
clickId.addEventListener('click', function() {
  console.log('My Name is Ray');
}) // Note: JavaScript events don't need the 'on' prefix

.box1 {
  border: 1px solid red;
  background: red;
  height: 200px;
}
.box2 {
  border: 1px solid blue;
  background: blue;
  color: white;
  height: 100px;
}

var box1 = document.getElementById('box1');
box1.addEventListener('click', function(e) {
  alert('box1');
  console.log('box1');
},true);

var box2 = document.getElementById('box2');
box2.addEventListener('click', function(e) {
  alert('box2');
  console.log('box2');
},true);
